(window.webpackJsonp=window.webpackJsonp||[]).push([[944],{1239:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">a</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">b</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> complexNumberMultiply = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">a, b</span>) </span>{\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">parse</span>(<span class=\\"hljs-params\\">str</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> arr=str.split(<span class=\\"hljs-string\\">\'+\'</span>)\\n    <span class=\\"hljs-keyword\\">let</span> a=<span class=\\"hljs-built_in\\">parseInt</span>(arr[<span class=\\"hljs-number\\">0</span>],<span class=\\"hljs-number\\">10</span>),\\n        b=<span class=\\"hljs-built_in\\">parseInt</span>(arr[<span class=\\"hljs-number\\">1</span>],<span class=\\"hljs-number\\">10</span>)\\n    <span class=\\"hljs-keyword\\">return</span> [a,b]\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> [x1,y1]=parse(a),[x2,y2]=parse(b)\\n  \\n  <span class=\\"hljs-keyword\\">let</span> intNum=x1*x2-y1*y2\\n  <span class=\\"hljs-keyword\\">let</span> complexNum=x1*y2+x2*y1\\n  \\n  <span class=\\"hljs-keyword\\">return</span> intNum+<span class=\\"hljs-string\\">\\"+\\"</span>+complexNum+<span class=\\"hljs-string\\">\\"i\\"</span>\\n};\\n</code></pre>\\n"],"titleSlug":"complex-number-multiplication","hasThinking":false,"content":"<p><a href=\\"https://baike.baidu.com/item/%E5%A4%8D%E6%95%B0/254365?fr=aladdin\\" target=\\"_blank\\">\u590d\u6570</a> \u53ef\u4ee5\u7528\u5b57\u7b26\u4e32\u8868\u793a\uff0c\u9075\u5faa <code>\\"<strong>\u5b9e\u90e8</strong>+<strong>\u865a\u90e8</strong>i\\"</code> \u7684\u5f62\u5f0f\uff0c\u5e76\u6ee1\u8db3\u4e0b\u8ff0\u6761\u4ef6\uff1a</p>\\n\\n<ul>\\n\\t<li><code>\u5b9e\u90e8</code> \u662f\u4e00\u4e2a\u6574\u6570\uff0c\u53d6\u503c\u8303\u56f4\u662f <code>[-100, 100]</code></li>\\n\\t<li><code>\u865a\u90e8</code> \u4e5f\u662f\u4e00\u4e2a\u6574\u6570\uff0c\u53d6\u503c\u8303\u56f4\u662f <code>[-100, 100]</code></li>\\n\\t<li><code>i<sup>2</sup> == -1</code></li>\\n</ul>\\n\\n<p>\u7ed9\u4f60\u4e24\u4e2a\u5b57\u7b26\u4e32\u8868\u793a\u7684\u590d\u6570 <code>num1</code> \u548c <code>num2</code> \uff0c\u8bf7\u4f60\u9075\u5faa\u590d\u6570\u8868\u793a\u5f62\u5f0f\uff0c\u8fd4\u56de\u8868\u793a\u5b83\u4eec\u4e58\u79ef\u7684\u5b57\u7b26\u4e32\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>num1 = \\"1+1i\\", num2 = \\"1+1i\\"\\n<strong>\u8f93\u51fa\uff1a</strong>\\"0+2i\\"\\n<strong>\u89e3\u91ca\uff1a</strong>(1 + i) * (1 + i) = 1 + i2 + 2 * i = 2i \uff0c\u4f60\u9700\u8981\u5c06\u5b83\u8f6c\u6362\u4e3a 0+2i \u7684\u5f62\u5f0f\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>num1 = \\"1+-1i\\", num2 = \\"1+-1i\\"\\n<strong>\u8f93\u51fa\uff1a</strong>\\"0+-2i\\"\\n<strong>\u89e3\u91ca\uff1a</strong>(1 - i) * (1 - i) = 1 + i2 - 2 * i = -2i \uff0c\u4f60\u9700\u8981\u5c06\u5b83\u8f6c\u6362\u4e3a 0+-2i \u7684\u5f62\u5f0f\u3002 \\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>num1</code> \u548c <code>num2</code> \u90fd\u662f\u6709\u6548\u7684\u590d\u6570\u8868\u793a\u3002</li>\\n</ul>\\n","title":"537. \u590d\u6570\u4e58\u6cd5","relatedTags":["\u6570\u5b66","\u5b57\u7b26\u4e32"],"difficult":"Middle","lang":["javascript"],"uniqueID":"537"}')}}]);